import { Router } from "express";
import { cancelMyBooking, createBooking, getAdminBookingById, getAllBookings, getMyBookingById, getMyBookings, getOwnerBookingById, getOwnerBookings, updateBookingStatus, updateMyBookingPayment, updateOwnerBookingStatus, } from "../controllers/booking.controller.js";
import { protect } from "../middlewares/auth.middleware.js";
import { adminOnly } from "../middlewares/admin.middleware.js";
import { ownerOnly } from "../middlewares/owner.middleware.js";
import { userOnly } from "../middlewares/user.middleware.js";
const router = Router();
router.post("/", protect, userOnly, createBooking);
router.get("/my-bookings", protect, userOnly, getMyBookings);
router.get("/my-bookings/:id", protect, userOnly, getMyBookingById);
router.patch("/:id/cancel", protect, userOnly, cancelMyBooking);
router.patch("/:id/payment", protect, userOnly, updateMyBookingPayment);
router.get("/owner/my-bookings", protect, ownerOnly, getOwnerBookings);
router.get("/owner/my-bookings/:id", protect, ownerOnly, getOwnerBookingById);
router.patch("/owner/:id/status", protect, ownerOnly, updateOwnerBookingStatus);
router.get("/admin/:id", protect, adminOnly, getAdminBookingById);
router.get("/", protect, adminOnly, getAllBookings);
router.patch("/:id/status", protect, adminOnly, updateBookingStatus);
export default router;
